      )}

      {/* ── My History ── */}
      {tab === 'history' && (
        <>
          <div className="filter-bar">
            {STATUS_HISTORY.map(({ value, label }) => (
              <button
                key={value}
                className={`filter-chip ${historyFilter === value ? 'active' : ''}`}
                onClick={() => setHistoryFilter(value)}
              >
                {label}
              </button>
            ))}
          </div>
          {loadReq ? (
            <SkeletonCard />
          ) : filteredMyReqs.length === 0 ? (
            <div className="card">
              <div style={{ textAlign: 'center', padding: '40px 20px', color: 'var(--text-muted)' }}>
                No leave requests found
              </div>
            </div>
          ) : (
            <div className="table-wrap">
              <table>
                <thead>
                  <tr>
                    <th>Leave Type</th>
                    <th>Period</th>
                    <th>Days</th>
                    <th>Status</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredMyReqs.map((req, i) => (
                    <RequestRow
                      key={req.LeaveRequestID || req.leaveRequestId || req.id || i}
                      req={req}
                      onAction={handleAction}
                      isManager={false}
                      userRole={user?.role}
                    />
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </>
      )}

      {/* ── All Requests (HR/Admin) ── */}
      {tab === 'all' && isManager && (
        <>
          <div className="filter-bar">
            {STATUS_OPTIONS.map(({ value, label }) => (
              <button
                key={value}
                className={`filter-chip ${allFilter === value ? 'active' : ''}`}
                onClick={() => setAllFilter(value)}
              >
                {label}
              </button>
            ))}
          </div>
          {loadAll ? (
            <SkeletonCard />
          ) : filteredAllReqs.length === 0 ? (
            <div className="card">
              <div style={{ textAlign: 'center', padding: '40px 20px', color: 'var(--text-muted)' }}>
                {allFilter ? `No ${allFilter.toLowerCase()} requests found` : 'No leave requests found'}
              </div>
            </div>
          ) : (
            <div className="table-wrap">
              <table>
                <thead>
                  <tr>
                    <th>Leave Type</th>
                    <th>Employee</th>
                    <th>Period</th>
                    <th>Days</th>
                    <th>Status</th>
                    <th>Reason</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredAllReqs.map((req, i) => (
                    <RequestRow
                      key={req.LeaveRequestID || req.id || i}
                      req={req}
                      onAction={handleAction}
                      isManager={true}
                      userRole={user?.role}
                    />
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </>
      )}
    </>
  );
}
